import{_ as e,c as s,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"工具集詳解: 掌握記憶操作 | opencode-supermemory","description":"掌握 supermemory 工具的 5 種核心模式（add, search, profile, list, forget），學會透過自然語言指令控制 Agent 的記憶行為。","frontmatter":{"title":"工具集詳解: 掌握記憶操作 | opencode-supermemory","sidebarTitle":"工具集","subtitle":"工具集詳解：教 Agent 記憶","description":"掌握 supermemory 工具的 5 種核心模式（add, search, profile, list, forget），學會透過自然語言指令控制 Agent 的記憶行為。","tags":["工具使用","記憶管理","核心功能"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"zh-tw/supermemoryai/opencode-supermemory/core/tools/index.md","filePath":"zh-tw/supermemoryai/opencode-supermemory/core/tools/index.md"}'),o={name:"zh-tw/supermemoryai/opencode-supermemory/core/tools/index.md"};function n(r,t,p,l,d,h){return a(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="工具集詳解-教-agent-記憶" tabindex="-1">工具集詳解：教 Agent 記憶 <a class="header-anchor" href="#工具集詳解-教-agent-記憶" aria-label="Permalink to &quot;工具集詳解：教 Agent 記憶&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><p>在這一課，你將掌握 <code>supermemory</code> 外掛的核心互動方式。雖然 Agent 通常會自動管理記憶，但作為開發者，你經常需要手動干預。</p><p>學完本課，你將能夠：</p><ol><li>使用 <code>add</code> 模式手動儲存關鍵技術決策。</li><li>使用 <code>search</code> 模式驗證 Agent 是否記住了你的偏好。</li><li>使用 <code>profile</code> 查看 Agent 眼中的「你」。</li><li>使用 <code>list</code> 和 <code>forget</code> 清理過時或錯誤的記憶。</li></ol><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>opencode-supermemory 並不是一個黑盒，它透過標準的 OpenCode Tool 協議與 Agent 互動。這意味著你可以像呼叫函數一樣呼叫它，也可以用自然語言指揮 Agent 使用它。</p><p>外掛向 Agent 註冊了一個名為 <code>supermemory</code> 的工具，它就像一把瑞士軍刀，擁有 6 種模式：</p><table tabindex="0"><thead><tr><th>模式</th><th>作用</th><th>典型場景</th></tr></thead><tbody><tr><td><strong>add</strong></td><td>新增記憶</td><td>&quot;記住，這個專案必須用 Bun 執行&quot;</td></tr><tr><td><strong>search</strong></td><td>搜尋記憶</td><td>&quot;我之前有沒有說過怎麼處理驗證？&quot;</td></tr><tr><td><strong>profile</strong></td><td>使用者設定檔</td><td>查看 Agent 總結你的編碼習慣</td></tr><tr><td><strong>list</strong></td><td>列出記憶</td><td>審計最近儲存的 10 條記憶</td></tr><tr><td><strong>forget</strong></td><td>刪除記憶</td><td>刪除一條錯誤的配置記錄</td></tr><tr><td><strong>help</strong></td><td>使用指南</td><td>查看工具說明文件</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">自動觸發機制</p><p>除了手動呼叫，外掛還會監聽你的聊天內容。當你透過自然語言說出 &quot;Remember this&quot; 或 &quot;Save this&quot; 時，外掛會自動偵測關鍵詞，並強制 Agent 呼叫 <code>add</code> 工具。</p></div><h2 id="跟我做-手動管理記憶" tabindex="-1">跟我做：手動管理記憶 <a class="header-anchor" href="#跟我做-手動管理記憶" aria-label="Permalink to &quot;跟我做：手動管理記憶&quot;">​</a></h2><p>雖然我們通常讓 Agent 自動操作，但在除錯或建立初始記憶時，手動呼叫工具非常有用。你可以在 OpenCode 的對話框中直接透過自然語言讓 Agent 執行這些操作。</p><h3 id="_1-新增記憶-add" tabindex="-1">1. 新增記憶 (Add) <a class="header-anchor" href="#_1-新增記憶-add" aria-label="Permalink to &quot;1. 新增記憶 (Add)&quot;">​</a></h3><p>這是最常用的功能。你可以指定記憶的內容、類型和作用域。</p><p><strong>操作</strong>：告訴 Agent 儲存一條關於專案架構的記憶。</p><p><strong>輸入指令</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用 supermemory 工具儲存一條記憶：</span></span>
<span class="line"><span>內容：「本專案的所有服務層程式碼都必須放在 src/services 目錄下」</span></span>
<span class="line"><span>類型：architecture</span></span>
<span class="line"><span>範圍：project</span></span></code></pre></div><p><strong>Agent 的內部行為</strong>（原始碼邏輯）：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;supermemory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;add&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;content&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;本專案的所有服務層程式碼都必須放在 src/services 目錄下&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;architecture&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;scope&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;project&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>你應該看到</strong>： Agent 回傳類似這樣的確認資訊：</p><blockquote><p>✅ Memory added to project scope (ID: mem_12345...)</p></blockquote><div class="tip custom-block"><p class="custom-block-title">記憶類型 (Type) 的選擇</p><p>為了讓檢索更精準，建議使用準確的類型：</p><ul><li><code>project-config</code>: 技術堆疊、工具鏈配置</li><li><code>architecture</code>: 架構模式、目錄結構</li><li><code>preference</code>: 你的個人編碼喜好（如「喜歡箭頭函數」）</li><li><code>error-solution</code>: 某個報錯的特定解決方案</li><li><code>learned-pattern</code>: Agent 觀察到的程式碼模式</li></ul></div><h3 id="_2-搜尋記憶-search" tabindex="-1">2. 搜尋記憶 (Search) <a class="header-anchor" href="#_2-搜尋記憶-search" aria-label="Permalink to &quot;2. 搜尋記憶 (Search)&quot;">​</a></h3><p>當你想確認 Agent 是否「知道」某件事時，可以使用搜尋功能。</p><p><strong>操作</strong>：搜尋關於「服務層」的記憶。</p><p><strong>輸入指令</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查詢 supermemory，關鍵詞是&quot;services&quot;，範圍是 project</span></span></code></pre></div><p><strong>Agent 的內部行為</strong>：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;supermemory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;search&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;query&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;services&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;scope&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;project&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>你應該看到</strong>： Agent 列出相關的記憶片段及其相似度（Similarity）。</p><h3 id="_3-查看使用者設定檔-profile" tabindex="-1">3. 查看使用者設定檔 (Profile) <a class="header-anchor" href="#_3-查看使用者設定檔-profile" aria-label="Permalink to &quot;3. 查看使用者設定檔 (Profile)&quot;">​</a></h3><p>Supermemory 會自動維護一個「使用者設定檔」，包含你的長期偏好。</p><p><strong>操作</strong>：查看你的設定檔。</p><p><strong>輸入指令</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>呼叫 supermemory 工具的 profile 模式，看看你對我有什麼了解</span></span></code></pre></div><p><strong>你應該看到</strong>： 回傳兩類資訊：</p><ul><li><strong>Static</strong>: 靜態事實（如「使用者是全端工程師」）</li><li><strong>Dynamic</strong>: 動態偏好（如「使用者最近在關注 Rust」）</li></ul><h3 id="_4-審計與遺忘-list-forget" tabindex="-1">4. 審計與遺忘 (List &amp; Forget) <a class="header-anchor" href="#_4-審計與遺忘-list-forget" aria-label="Permalink to &quot;4. 審計與遺忘 (List &amp; Forget)&quot;">​</a></h3><p>如果 Agent 記住了錯誤的資訊（比如一個已經廢棄的 API Key），你需要刪除它。</p><p><strong>第一步：列出最近記憶</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>列出最近的 5 條專案記憶</span></span></code></pre></div><p><em>(Agent 呼叫 <code>mode: &quot;list&quot;, limit: 5</code>)</em></p><p><strong>第二步：取得 ID 並刪除</strong> 假設你看到一條錯誤的記憶 ID 為 <code>mem_abc123</code>。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>刪除記憶 ID 為 mem_abc123 的記錄</span></span></code></pre></div><p><em>(Agent 呼叫 <code>mode: &quot;forget&quot;, memoryId: &quot;mem_abc123&quot;</code>)</em></p><p><strong>你應該看到</strong>：</p><blockquote><p>✅ Memory mem_abc123 removed from project scope</p></blockquote><h2 id="進階-自然語言觸發" tabindex="-1">進階：自然語言觸發 <a class="header-anchor" href="#進階-自然語言觸發" aria-label="Permalink to &quot;進階：自然語言觸發&quot;">​</a></h2><p>你不需要每次都詳細描述工具參數。外掛內建了關鍵詞偵測機制。</p><p><strong>試一試</strong>： 在對話中直接說：</p><blockquote><p><strong>Remember this</strong>: 所有的日期處理都必須使用 date-fns 函式庫，禁止使用 moment.js。</p></blockquote><p><strong>發生了什麼？</strong></p><ol><li>外掛的 <code>chat.message</code> 鉤子偵測到關鍵詞 &quot;Remember this&quot;。</li><li>外掛向 Agent 注入了一個系統提示：<code>[MEMORY TRIGGER DETECTED]</code>。</li><li>Agent 收到指令：&quot;You MUST use the supermemory tool with mode: &#39;add&#39;...&quot;。</li><li>Agent 自動提取內容並呼叫工具。</li></ol><p>這是一個非常自然的互動方式，讓你在編碼過程中隨時「固化」知識。</p><h2 id="常見問題-faq" tabindex="-1">常見問題 (FAQ) <a class="header-anchor" href="#常見問題-faq" aria-label="Permalink to &quot;常見問題 (FAQ)&quot;">​</a></h2><p><strong>Q: <code>scope</code> 預設是什麼？</strong> A: 預設為 <code>project</code>。如果你想儲存跨專案通用的偏好（比如「我總是使用 TypeScript」），請明確指定 <code>scope: &quot;user&quot;</code>。</p><p><strong>Q: 為什麼我新增的記憶沒有立即生效？</strong> A: <code>add</code> 操作是非同步的。通常 Agent 會在工具呼叫成功後立即「知道」這條新記憶，但在某些極端網路延遲下可能需要幾秒鐘。</p><p><strong>Q: 敏感資訊會被上傳嗎？</strong> A: 外掛會自動脫敏 <code>&lt;private&gt;</code> 標籤內的內容。但為了安全，建議不要將密碼或 API Key 放入記憶中。</p><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>工具定義</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L183-L485" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>183-485</td></tr><tr><td>關鍵詞偵測</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L34-L37" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>34-37</td></tr><tr><td>觸發提示詞</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L20-L28" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>20-28</td></tr><tr><td>客戶端實作</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/client.ts" target="_blank" rel="noreferrer"><code>src/services/client.ts</code></a></td><td>全文</td></tr></tbody></table><p><strong>關鍵類型定義</strong>：</p><ul><li><code>MemoryType</code>: 定義在 <a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/types/index.ts" target="_blank" rel="noreferrer"><code>src/types/index.ts</code></a></li><li><code>MemoryScope</code>: 定義在 <a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/types/index.ts" target="_blank" rel="noreferrer"><code>src/types/index.ts</code></a></li></ul></details><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../memory-management/">記憶作用域與生命週期</a></strong>。</p><p>你會學到：</p><ul><li>User Scope 和 Project Scope 的底層隔離機制</li><li>如何設計高效的記憶分區策略</li><li>記憶的生命週期管理</li></ul></blockquote>`,63)])])}const u=e(o,[["render",n]]);export{g as __pageData,u as default};
